fn primary_expression_transport_to_any(t: PrimaryExpressionTransport) -> AnyTransport {
    match t {
        PrimaryExpressionTransport::SubscriptExpression(inner) => AnyTransport::SubscriptExpression(inner),
        PrimaryExpressionTransport::MemberExpression(inner) => AnyTransport::MemberExpression(inner),
        PrimaryExpressionTransport::ParenthesizedExpression(inner) => AnyTransport::ParenthesizedExpression(inner),
        PrimaryExpressionTransport::_Identifier(inner) => _identifier_transport_to_any(inner),
        PrimaryExpressionTransport::Undefined(inner) => AnyTransport::Undefined(inner),
        PrimaryExpressionTransport::Identifier(inner) => AnyTransport::Identifier(inner),
        PrimaryExpressionTransport::ReservedIdentifier(inner) => AnyTransport::ReservedIdentifier(inner),
        PrimaryExpressionTransport::This(inner) => AnyTransport::This(inner),
        PrimaryExpressionTransport::Super(inner) => AnyTransport::Super(inner),
        PrimaryExpressionTransport::Number(inner) => AnyTransport::Number(inner),
        PrimaryExpressionTransport::String(inner) => AnyTransport::String(inner),
        PrimaryExpressionTransport::TemplateString(inner) => AnyTransport::TemplateString(inner),
        PrimaryExpressionTransport::Regex(inner) => AnyTransport::Regex(inner),
        PrimaryExpressionTransport::True(inner) => AnyTransport::True(inner),
        PrimaryExpressionTransport::False(inner) => AnyTransport::False(inner),
        PrimaryExpressionTransport::Null(inner) => AnyTransport::Null(inner),
        PrimaryExpressionTransport::Object(inner) => AnyTransport::Object(inner),
        PrimaryExpressionTransport::Array(inner) => AnyTransport::Array(inner),
        PrimaryExpressionTransport::FunctionExpression(inner) => AnyTransport::FunctionExpression(inner),
        PrimaryExpressionTransport::ArrowFunction(inner) => AnyTransport::ArrowFunction(inner),
        PrimaryExpressionTransport::GeneratorFunction(inner) => AnyTransport::GeneratorFunction(inner),
        PrimaryExpressionTransport::Class(inner) => AnyTransport::Class(inner),
        PrimaryExpressionTransport::MetaProperty(inner) => AnyTransport::MetaProperty(inner),
        PrimaryExpressionTransport::CallExpression(inner) => AnyTransport::CallExpression(inner),
        PrimaryExpressionTransport::NonNullExpression(inner) => AnyTransport::NonNullExpression(inner),
        PrimaryExpressionTransport::Verbatim(inner) => AnyTransport::Verbatim(inner),
    }
}

impl RenderableTransport for PrimaryExpressionTransport {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        render_primary_expression(self, dest)
    }
}

