#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AccessibilityModifierEnum {
    PublicKw,
    PrivateKw,
    ProtectedKw,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for AccessibilityModifierEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        match transport_value_type(env, napi_val)? {
            ::napi::ValueType::Number => {
                if let Ok(kind_id) = u16::from_napi_value(env, napi_val) {
                    match kind_id {
                        121 => return Ok(Self::PublicKw), // "public"
                        122 => return Ok(Self::PrivateKw), // "private"
                        123 => return Ok(Self::ProtectedKw), // "protected"
                        _ => {}
                    }
                }
            }
            ::napi::ValueType::String => {
                match String::from_napi_value(env, napi_val)?.as_str() {
                    "public" => return Ok(Self::PublicKw),
                    "private" => return Ok(Self::PrivateKw),
                    "protected" => return Ok(Self::ProtectedKw),
                    _ => {}
                }
            }
            ::napi::ValueType::Object => {
                let obj = ::napi::bindgen_prelude::Object::from_napi_value(env, napi_val)?;
                if let Some(kind_id) = obj.get::<u16>("$type")? {
                    match kind_id {
                        121 => return Ok(Self::PublicKw), // "public"
                        122 => return Ok(Self::PrivateKw), // "private"
                        123 => return Ok(Self::ProtectedKw), // "protected"
                        _ => {}
                    }
                }
                if let Some(text) = obj.get::<String>("$text")? {
                    match text.as_str() {
                        "public" => return Ok(Self::PublicKw),
                        "private" => return Ok(Self::PrivateKw),
                        "protected" => return Ok(Self::ProtectedKw),
                        _ => {}
                    }
                }
                if obj.get::<::napi::bindgen_prelude::Object>("_public")?.is_some() { return Ok(Self::PublicKw); }
                if obj.get::<::napi::bindgen_prelude::Object>("_private")?.is_some() { return Ok(Self::PrivateKw); }
                if obj.get::<::napi::bindgen_prelude::Object>("_protected")?.is_some() { return Ok(Self::ProtectedKw); }
            }
            _ => {}
        }
        Err(::napi::Error::from_reason("unknown enum payload for AccessibilityModifierEnum"))
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for AccessibilityModifierEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("AccessibilityModifierEnum is receive-only"))
    }
}

impl ::std::fmt::Display for AccessibilityModifierEnum {
    fn fmt(&self, f: &mut ::std::fmt::Formatter<'_>) -> ::std::fmt::Result {
        f.write_str(match self {
            Self::PublicKw => "public",
            Self::PrivateKw => "private",
            Self::ProtectedKw => "protected",
        })
    }
}

impl RenderableTransport for AccessibilityModifierEnum {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        dest.write_str(match self {
            Self::PublicKw => "public",
            Self::PrivateKw => "private",
            Self::ProtectedKw => "protected",
        }).map_err(::askama::Error::from)
    }
}

