        let transport_child_index = obj.get("$childIndex")?;
        let transport_trivia_data = obj.get("$triviaData")?;
        Ok(Self {
            transport_source,
            transport_named,
            transport_span,
            transport_node_handle,
            transport_child_index,
            transport_trivia_data,
            text,
        })
