#[cfg(all(feature = "napi-bindings", not(feature = "debug-transport")))]
impl ::napi::bindgen_prelude::FromNapiValue for OverrideModifierTransport {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let text = match transport_value_type(env, napi_val)? {
            ::napi::ValueType::String => String::from_napi_value(env, napi_val)?,
            // Raw kind_id: value-less leaf sent as its numeric kind tag.
            ::napi::ValueType::Number => "override".to_string(),
            ::napi::ValueType::Boolean => {
                if !bool::from_napi_value(env, napi_val)? {
                    return Err(::napi::Error::from_reason("OverrideModifierTransport received false; omit the field instead of sending false"));
                }
                "override".to_string()
            }
            _ => {
                let obj = ::napi::bindgen_prelude::Object::from_napi_value(env, napi_val)?;
                obj.get("$text")?.unwrap_or_else(|| "override".to_string())
            }
        };
        Ok(Self {
            transport_source: None,
            transport_named: Some(true),
            transport_span: None,
            transport_node_handle: None,
            transport_child_index: None,
            transport_trivia_data: None,
            text,
        })
    }
}

#[cfg(all(feature = "napi-bindings", feature = "debug-transport"))]
impl ::napi::bindgen_prelude::FromNapiValue for OverrideModifierTransport {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        match transport_value_type(env, napi_val)? {
            ::napi::ValueType::String => {
                let text = String::from_napi_value(env, napi_val)?;
                return Ok(Self {
                    transport_source: None,
                    transport_named: Some(true),
                    transport_span: None,
                    transport_node_handle: None,
                    transport_child_index: None,
                    transport_trivia_data: None,
                    text,
                });
            }
            ::napi::ValueType::Boolean => {
                if !bool::from_napi_value(env, napi_val)? {
                    return Err(::napi::Error::from_reason("OverrideModifierTransport received false; omit the field instead of sending false"));
                }
                return Ok(Self {
                    transport_source: None,
                    transport_named: Some(true),
                    transport_span: None,
                    transport_node_handle: None,
                    transport_child_index: None,
                    transport_trivia_data: None,
                    text: "override".to_string(),
                });
            }
            _ => {}
        }
        let obj = ::napi::bindgen_prelude::Object::from_napi_value(env, napi_val)?;
        let text: String = obj.get("$text")?.unwrap_or_else(|| "override".to_string());
        let transport_source = obj.get("$source")?;
        let transport_named = obj.get("$named")?;
        let transport_span = obj.get("$span")?;
        let transport_node_handle = obj.get("$nodeHandle")?;
        let transport_child_index = obj.get("$childIndex")?;
        let transport_trivia_data = obj.get("$triviaData")?;
        Ok(Self {
            transport_source,
            transport_named,
            transport_span,
            transport_node_handle,
            transport_child_index,
            transport_trivia_data,
            text,
        })
    }
}

